function genId() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2, 8);
}

function todayISO() {
  return new Date().toISOString().slice(0, 10);
}

function fmtMoney(n) {
  const num = Number(n) || 0;
  return "$" + num.toLocaleString("es-MX", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function avanceProgreso(student) {
  const vals = MODULES.map(m => student.avance?.[m.key] || "pendiente");
  const done = vals.filter(v => v === "completado").length;
  const partial = vals.filter(v => v === "progreso").length;
  return Math.round(((done + partial * 0.5) / MODULES.length) * 100);
}

