function LoginScreen({ users, onLogin }) {
  const activeUsers = users.filter(u => u.estado === "Activo");
  const [userId, setUserId] = useState(activeUsers[0]?.id || "");
  const [pwd, setPwd] = useState("");
  const [err, setErr] = useState("");
  const [shake, setShake] = useState(false);
  const [loading, setLoading] = useState(false);

  async function handleSubmit() {
    setLoading(true);
    try {
      await onLogin(userId, pwd);
      setErr("");
    } catch (e) {
      setErr("Contraseña incorrecta. Intenta de nuevo.");
      setShake(true);
      setTimeout(() => setShake(false), 420);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div
      className="ij-serif"
      style={{
        minHeight: "100vh", width: "100%", background: C.verdeJusto,
        display: "flex", alignItems: "center", justifyContent: "center", padding: 20,
        backgroundImage: `radial-gradient(circle at 20% 20%, ${C.verdeEsencia}55, transparent 45%), radial-gradient(circle at 85% 80%, ${C.verdeEsencia}44, transparent 45%)`,
      }}
    >
      <style>{`
        @keyframes ijshake { 10%,90%{transform:translateX(-1px);} 20%,80%{transform:translateX(2px);} 30%,50%,70%{transform:translateX(-4px);} 40%,60%{transform:translateX(4px);} }
        .ij-shake { animation: ijshake .4s; }
        .ij-login-input:focus { border-color: ${C.oroJusto} !important; box-shadow: 0 0 0 3px ${C.oroJusto}22; }
      `}</style>
      <div
        className={shake ? "ij-shake" : ""}
        style={{
          background: "#FBF9F4", borderRadius: 18, padding: "40px 36px 32px 36px",
          width: "100%", maxWidth: 380, boxShadow: "0 30px 80px rgba(0,0,0,0.35)",
          textAlign: "center",
        }}
      >
        <img src={`data:image/png;base64,${ESCUDO_B64}`} alt="Escudo Instituto Justo" style={{ width: 76, margin: "0 auto 14px auto", display: "block" }} />
        <div className="ij-sans" style={{ fontSize: 13, letterSpacing: 4, color: C.verdeJusto, fontWeight: 500 }}>INSTITUTO</div>
        <div className="ij-serif" style={{ fontSize: 28, fontWeight: 700, color: C.verdeJusto, letterSpacing: 1, marginTop: -2 }}>JUSTO</div>
        <div className="ij-sans" style={{ fontSize: 10, letterSpacing: 2, color: C.oroJusto, fontWeight: 600, marginTop: 4, marginBottom: 26 }}>
          EL CONOCIMIENTO SE CONSTRUYE
        </div>

        <div style={{ height: 1, background: "#E3DCC4", margin: "0 0 24px 0" }} />

        <div className="ij-sans" style={{ fontSize: 13, color: "#7a7a72", marginBottom: 18, fontWeight: 500 }}>
          Campus Justo &middot; Acceso administrativo
        </div>

        <label className="ij-sans" style={{ display: "block", textAlign: "left", marginBottom: 12 }}>
          <span style={{ fontSize: 11, fontWeight: 600, color: C.verdeEsencia, textTransform: "uppercase", letterSpacing: 0.5, display: "block", marginBottom: 5 }}>
            Usuario
          </span>
          <div style={{ position: "relative" }}>
            <UserCircle2 size={16} color="#9a9484" style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)" }} />
            <select
              value={userId}
              onChange={e => { setUserId(e.target.value); setErr(""); }}
              style={{
                width: "100%", boxSizing: "border-box", padding: "12px 14px 12px 40px",
                borderRadius: 10, border: "1.5px solid #DCD5BF", fontSize: 14.5,
                fontFamily: "'Lora', serif", outline: "none", background: "#fff", color: C.grisCarbon,
                appearance: "none",
              }}
            >
              {activeUsers.length === 0 && <option>No hay usuarios activos</option>}
              {activeUsers.map(u => <option key={u.id} value={u.id}>{u.nombre} · {u.rol}</option>)}
            </select>
            <ChevronDown size={15} color="#9a9484" style={{ position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)", pointerEvents: "none" }} />
          </div>
        </label>

        <label className="ij-sans" style={{ display: "block", textAlign: "left", marginBottom: 4 }}>
          <span style={{ fontSize: 11, fontWeight: 600, color: C.verdeEsencia, textTransform: "uppercase", letterSpacing: 0.5, display: "block", marginBottom: 5 }}>
            Contraseña
          </span>
          <div style={{ position: "relative" }}>
            <Lock size={16} color="#9a9484" style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)" }} />
            <input
              type="password"
              value={pwd}
              onChange={e => { setPwd(e.target.value); setErr(""); }}
              onKeyDown={e => e.key === "Enter" && handleSubmit()}
              placeholder="Contraseña"
              className="ij-login-input"
              style={{
                width: "100%", boxSizing: "border-box", padding: "13px 14px 13px 40px",
                borderRadius: 10, border: `1.5px solid ${err ? "#B5533C" : "#DCD5BF"}`,
                fontSize: 15, fontFamily: "'Lora', serif", outline: "none", background: "#fff",
                color: C.grisCarbon,
              }}
            />
          </div>
        </label>

        {err && (
          <div className="ij-sans" style={{ color: "#B5533C", fontSize: 12.5, textAlign: "left", margin: "8px 0", display: "flex", alignItems: "center", gap: 6 }}>
            <AlertCircle size={14} /> {err}
          </div>
        )}

        <button
          onClick={handleSubmit}
          className="ij-sans"
          style={{
            width: "100%", background: C.oroJusto, color: "#fff", border: "none",
            padding: "13px 0", borderRadius: 10, fontWeight: 700, fontSize: 14.5,
            marginTop: 14, cursor: "pointer", letterSpacing: 0.3,
            boxShadow: "0 6px 18px rgba(200,162,64,0.4)",
          }}
        >
          Ingresar
        </button>

        <div className="ij-sans" style={{ marginTop: 22, fontSize: 10.5, color: "#a39c86", lineHeight: 1.6 }}>
          Prototipo de demostración. Contraseñas iniciales:<br />
          Manuel → <code style={{ background: "#F0ECDD", padding: "1px 6px", borderRadius: 4 }}>manuel2026</code>
          &nbsp;&middot;&nbsp;
          Luis → <code style={{ background: "#F0ECDD", padding: "1px 6px", borderRadius: 4 }}>luis2026</code>
        </div>
      </div>
    </div>
  );
}

