function NewSaleModal({ materials, students, currentUser, onClose, onCreate }) {
  const [materialId, setMaterialId] = useState(materials[0]?.id || "");
  const [cantidad, setCantidad] = useState("1");
  const [alumnoId, setAlumnoId] = useState("");
  const [fecha, setFecha] = useState(todayISO());

  const material = materials.find(m => m.id === materialId);
  const total = material ? Number(material.precio) * (Number(cantidad) || 0) : 0;
  const canSave = materialId && Number(cantidad) > 0;

  function handleSave() {
    if (!canSave || !material) return;
    const alumno = students.find(s => s.id === alumnoId);
    onCreate({
      id: genId(), fecha, itemId: material.id, itemNombre: material.nombre,
      cantidad: Number(cantidad), precioUnitario: material.precio, total,
      alumno: alumno ? alumno.nombre : "", registradoPor: currentUser?.nombre || "—",
    });
    onClose();
  }

  return (
    <Modal title="Registrar venta de material" onClose={onClose}>
      <label className="ij-sans" style={{ display: "block", marginBottom: 14 }}>
        <span style={{ fontSize: 11.5, fontWeight: 600, color: C.verdeEsencia, textTransform: "uppercase", letterSpacing: 0.4, display: "block", marginBottom: 5 }}>
          Material <span style={{ color: "#B5533C" }}>*</span>
        </span>
        <select
          value={materialId}
          onChange={e => setMaterialId(e.target.value)}
          style={{ width: "100%", boxSizing: "border-box", padding: "9px 12px", borderRadius: 8, border: "1px solid #DCD5BF", fontSize: 14, fontFamily: "'Lora', serif", color: C.grisCarbon, outline: "none", background: "#fff" }}
        >
          {materials.map(m => <option key={m.id} value={m.id}>{m.nombre} &middot; {fmtMoney(m.precio)}</option>)}
        </select>
      </label>

      <div style={{ display: "flex", gap: 12 }}>
        <div style={{ flex: 1 }}><FieldInput label="Cantidad" type="number" value={cantidad} onChange={setCantidad} required /></div>
        <div style={{ flex: 1 }}><FieldInput label="Fecha" type="date" value={fecha} onChange={setFecha} /></div>
      </div>

      <label className="ij-sans" style={{ display: "block", marginBottom: 14 }}>
        <span style={{ fontSize: 11.5, fontWeight: 600, color: C.verdeEsencia, textTransform: "uppercase", letterSpacing: 0.4, display: "block", marginBottom: 5 }}>
          Alumno (opcional)
        </span>
        <select
          value={alumnoId}
          onChange={e => setAlumnoId(e.target.value)}
          style={{ width: "100%", boxSizing: "border-box", padding: "9px 12px", borderRadius: 8, border: "1px solid #DCD5BF", fontSize: 14, fontFamily: "'Lora', serif", color: C.grisCarbon, outline: "none", background: "#fff" }}
        >
          <option value="">Venta general (sin asociar)</option>
          {students.map(s => <option key={s.id} value={s.id}>{s.nombre}</option>)}
        </select>
      </label>

      <div style={{ background: "#FBF9F4", border: "1px solid #EBE6D8", borderRadius: 10, padding: "12px 16px", marginBottom: 16, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <span className="ij-sans" style={{ fontSize: 12, color: "#8a8168", textTransform: "uppercase", letterSpacing: 0.5 }}>Total de la venta</span>
        <span className="ij-serif" style={{ fontSize: 20, fontWeight: 700, color: C.verdeJusto }}>{fmtMoney(total)}</span>
      </div>

      <PrimaryButton icon={Save} onClick={handleSave} full>Registrar venta</PrimaryButton>
    </Modal>
  );
}

function NewCashboxModal({ currentUser, onClose, onCreate }) {
  const [tipo, setTipo] = useState("Entrada");
  const [concepto, setConcepto] = useState("");
  const [monto, setMonto] = useState("");
  const [fecha, setFecha] = useState(todayISO());

  const canSave = concepto.trim() && Number(monto) > 0;

  function handleSave() {
    if (!canSave) return;
    onCreate({ id: genId(), fecha, tipo, concepto, monto: Number(monto), registradoPor: currentUser?.nombre || "—" });
    onClose();
  }

  return (
    <Modal title="Nuevo movimiento de caja chica" onClose={onClose}>
      <div style={{ display: "flex", gap: 8, marginBottom: 16 }}>
        {["Entrada", "Salida"].map(t => (
          <button
            key={t}
            onClick={() => setTipo(t)}
            className="ij-sans"
            style={{
              flex: 1, padding: "12px 0", borderRadius: 9, cursor: "pointer", fontWeight: 700, fontSize: 13.5,
              border: `1.5px solid ${tipo === t ? (t === "Entrada" ? C.verdeEsencia : "#B5533C") : "#DCD5BF"}`,
              background: tipo === t ? (t === "Entrada" ? "#EAF3EC" : "#FBEAE6") : "#fff",
              color: tipo === t ? (t === "Entrada" ? C.verdeEsencia : "#B5533C") : "#9a9484",
              display: "flex", alignItems: "center", justifyContent: "center", gap: 7,
            }}
          >
            {t === "Entrada" ? <ArrowDownCircle size={16} /> : <ArrowUpCircle size={16} />}
            {t}
          </button>
        ))}
      </div>
      <FieldInput label="Concepto" value={concepto} onChange={setConcepto} required placeholder={tipo === "Entrada" ? "Ej. Aportación de socio" : "Ej. Compra de papelería"} />
      <div style={{ display: "flex", gap: 12 }}>
        <div style={{ flex: 1 }}><FieldInput label="Monto (MXN)" type="number" value={monto} onChange={setMonto} required placeholder="500" /></div>
        <div style={{ flex: 1 }}><FieldInput label="Fecha" type="date" value={fecha} onChange={setFecha} /></div>
      </div>
      <PrimaryButton icon={Save} onClick={handleSave} full>Guardar movimiento</PrimaryButton>
    </Modal>
  );
}

export default function CampusJustoCRM() {
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState("dashboard");

  const [users, setUsers] = useState([]);
  const [students, setStudents] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [materials, setMaterials] = useState([]);
  const [sales, setSales] = useState([]);
  const [cashbox, setCashbox] = useState([]);

  const [selectedStudent, setSelectedStudent] = useState(null);
  const [showNewStudent, setShowNewStudent] = useState(false);
  const [showNewTeacher, setShowNewTeacher] = useState(false);
  const [showNewPayment, setShowNewPayment] = useState(false);
  const [paymentPreset, setPaymentPreset] = useState(null);
  const [showNewSale, setShowNewSale] = useState(false);
  const [showNewCashbox, setShowNewCashbox] = useState(false);
  const [showNewUser, setShowNewUser] = useState(false);
  const [saveError, setSaveError] = useState(false);

  useEffect(() => { loadAll(); }, []);

  async function loadAll() {
    setLoading(true);
    try {
      const data = await apiFetch("/api/bootstrap");
      setUsers(data.users);
      setStudents(data.students);
      setTeachers(data.teachers);
      setMaterials(data.materials);
      setSales(data.sales);
      setCashbox(data.cashbox);
    } catch (e) {
      setSaveError(true);
    }
    setLoading(false);
  }

  async function handleLogin(userId, password) {
    const { user } = await apiFetch("/api/auth/login", {
      method: "POST",
      body: JSON.stringify({ id: userId, password }),
    });
    setCurrentUser(user);
  }

  async function withSaveGuard(fn) {
    try {
      await fn();
      setSaveError(false);
    } catch (e) {
      setSaveError(true);
    }
  }

  // ---- Students ----
  function addStudent(s) {
    setStudents([...students, s]);
    withSaveGuard(() => apiFetch("/api/students", { method: "POST", body: JSON.stringify(s) }));
  }
  function updateStudent(updated) {
    const next = students.map(s => s.id === updated.id ? updated : s);
    setStudents(next);
    setSelectedStudent(updated);
    withSaveGuard(() => apiFetch(`/api/students/${updated.id}`, { method: "PATCH", body: JSON.stringify(updated) }));
  }
  function deleteStudent(id) {
    setStudents(students.filter(s => s.id !== id));
    setSelectedStudent(null);
    withSaveGuard(() => apiFetch(`/api/students/${id}`, { method: "DELETE" }));
  }
  function addPayment(studentId, payment) {
    const next = students.map(s => s.id === studentId ? { ...s, pagos: [...(s.pagos || []), payment] } : s);
    setStudents(next);
    if (selectedStudent && selectedStudent.id === studentId) {
      setSelectedStudent(next.find(s => s.id === studentId));
    }
    const updated = next.find(s => s.id === studentId);
    withSaveGuard(() => apiFetch(`/api/students/${studentId}`, { method: "PATCH", body: JSON.stringify(updated) }));
  }

  // ---- Teachers ----
  function addTeacher(t) {
    setTeachers([...teachers, t]);
    withSaveGuard(() => apiFetch("/api/teachers", { method: "POST", body: JSON.stringify(t) }));
  }
  function updateTeacher(updated) {
    setTeachers(teachers.map(t => t.id === updated.id ? updated : t));
    withSaveGuard(() => apiFetch(`/api/teachers/${updated.id}`, { method: "PATCH", body: JSON.stringify(updated) }));
  }
  function deleteTeacher(id) {
    setTeachers(teachers.filter(t => t.id !== id));
    withSaveGuard(() => apiFetch(`/api/teachers/${id}`, { method: "DELETE" }));
  }

  // ---- Materials & Sales ----
  function updateMaterialPrice(id, precio) {
    setMaterials(materials.map(m => m.id === id ? { ...m, precio } : m));
    withSaveGuard(() => apiFetch(`/api/materials/${id}`, { method: "PATCH", body: JSON.stringify({ precio }) }));
  }
  function addSale(sale) {
    setSales([...sales, sale]);
    const mat = materials.find(m => m.id === sale.itemId);
    if (mat) {
      const nextStock = Math.max(0, Number(mat.stock) - Number(sale.cantidad));
      setMaterials(materials.map(m => m.id === mat.id ? { ...m, stock: nextStock } : m));
    }
    withSaveGuard(() => apiFetch("/api/sales", { method: "POST", body: JSON.stringify(sale) }));
  }

  // ---- Cashbox ----
  function addCashbox(mov) {
    setCashbox([...cashbox, mov]);
    withSaveGuard(() => apiFetch("/api/cashbox", { method: "POST", body: JSON.stringify(mov) }));
  }

  // ---- Users ----
  function addUser(u) {
    setUsers([...users, u]);
    withSaveGuard(() => apiFetch("/api/users", { method: "POST", body: JSON.stringify(u) }));
  }
  function updateUser(updated) {
    setUsers(users.map(u => u.id === updated.id ? updated : u));
    if (currentUser && currentUser.id === updated.id) setCurrentUser(updated);
    withSaveGuard(() => apiFetch(`/api/users/${updated.id}`, { method: "PATCH", body: JSON.stringify(updated) }));
  }
  function deleteUser(id) {
    setUsers(users.filter(u => u.id !== id));
    withSaveGuard(() => apiFetch(`/api/users/${id}`, { method: "DELETE" }));
  }

  function openNewPayment(studentId) { setPaymentPreset(studentId); setShowNewPayment(true); }

  if (loading) {
    return (
      <div style={{ width: "100%", minHeight: "100vh", background: C.verdeJusto, display: "flex", alignItems: "center", justifyContent: "center", flexDirection: "column", gap: 12 }}>
        {FONTS}
        <img src={`data:image/png;base64,${ESCUDO_B64}`} alt="" style={{ width: 56, opacity: 0.9 }} />
        <div style={{ width: 30, height: 30, border: "3px solid rgba(255,255,255,0.25)", borderTopColor: C.oroJusto, borderRadius: "50%", animation: "spin 0.8s linear infinite" }} />
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        <div className="ij-sans" style={{ fontSize: 12.5, color: "#C9DCCF" }}>Cargando Campus Justo…</div>
      </div>
    );
  }

  if (!currentUser) {
    return (
      <div style={{ width: "100%", minHeight: "100vh" }}>
        {FONTS}
        <LoginScreen users={users} onLogin={handleLogin} />
      </div>
    );
  }

  const allData = { users, students, teachers, materials, sales, cashbox };

  return (
    <div className="ij-sans" style={{ width: "100%", minHeight: "100vh", background: C.grisClaro, display: "flex", flexDirection: "column" }}>
      {FONTS}
      <TopBar onLogout={() => setCurrentUser(null)} currentUser={currentUser} />
      <div style={{ display: "flex", flex: 1, minHeight: 0 }}>
        <Sidebar view={view} setView={setView} />
        <div className="ij-scrollbar" style={{ flex: 1, overflowY: "auto", minHeight: "calc(100vh - 60px)" }}>
          {view === "dashboard" && (
            <DashboardView
              students={students} teachers={teachers} sales={sales} cashbox={cashbox} setView={setView}
              openNewStudent={() => setShowNewStudent(true)}
              openNewTeacher={() => setShowNewTeacher(true)}
              openNewPayment={openNewPayment}
              openStudent={setSelectedStudent}
              openNewSale={() => setShowNewSale(true)}
              openNewCashbox={() => setShowNewCashbox(true)}
            />
          )}
          {view === "alumnos" && (
            <AlumnosView students={students} openStudent={setSelectedStudent} openNewStudent={() => setShowNewStudent(true)} />
          )}
          {view === "profesores" && (
            <ProfesoresView teachers={teachers} openNewTeacher={() => setShowNewTeacher(true)} onUpdate={updateTeacher} onDelete={deleteTeacher} />
          )}
          {view === "pagos" && (
            <PagosView students={students} openStudent={setSelectedStudent} openNewPayment={openNewPayment} />
          )}
          {view === "materiales" && (
            <MaterialesView materials={materials} sales={sales} currentUser={currentUser} onUpdatePrice={updateMaterialPrice} openNewSale={() => setShowNewSale(true)} />
          )}
          {view === "cajachica" && (
            <CajaChicaView cashbox={cashbox} openNewCashbox={() => setShowNewCashbox(true)} />
          )}
          {view === "cortemensual" && (
            <CorteMensualView students={students} sales={sales} cashbox={cashbox} />
          )}
          {view === "usuarios" && (
            <UsuariosView users={users} currentUser={currentUser} allData={allData} openNewUser={() => setShowNewUser(true)} onUpdate={updateUser} onDelete={deleteUser} />
          )}
        </div>
      </div>

      {selectedStudent && (
        <StudentDetail
          student={students.find(s => s.id === selectedStudent.id) || selectedStudent}
          onClose={() => setSelectedStudent(null)}
          onUpdate={updateStudent}
          onDelete={deleteStudent}
          openNewPayment={openNewPayment}
        />
      )}
      {showNewStudent && <NewStudentModal onClose={() => setShowNewStudent(false)} onCreate={addStudent} />}
      {showNewTeacher && <NewTeacherModal onClose={() => setShowNewTeacher(false)} onCreate={addTeacher} />}
      {showNewPayment && (
        <NewPaymentModal
          students={students} presetStudentId={paymentPreset} currentUser={currentUser}
          onClose={() => setShowNewPayment(false)} onCreate={addPayment}
        />
      )}
      {showNewSale && (
        <NewSaleModal materials={materials} students={students} currentUser={currentUser} onClose={() => setShowNewSale(false)} onCreate={addSale} />
      )}
      {showNewCashbox && (
        <NewCashboxModal currentUser={currentUser} onClose={() => setShowNewCashbox(false)} onCreate={addCashbox} />
      )}
      {showNewUser && <NewUserModal onClose={() => setShowNewUser(false)} onCreate={addUser} />}

      {saveError && (
        <div style={{ position: "fixed", bottom: 16, right: 16, background: "#B5533C", color: "#fff", padding: "10px 16px", borderRadius: 8, fontSize: 12.5, zIndex: 60 }} className="ij-sans">
          No se pudo guardar el cambio. Verifica tu conexión e intenta de nuevo.
        </div>
      )}
    </div>
  );
}
